from collections import defaultdict

def group_websites(queries):
    hostname_to_path = defaultdict(list)

    for query in queries:
        hostname, path = query.split('/')
        hostname_to_path[hostname].append(path)

    groups = []
    seen = set()

    for hostname, paths in hostname_to_path.items():
        if len(paths) > 1:
            for path in paths:
                if path not in seen:
                    seen.add(path)
                    groups.append(hostname)
                    break

    return len(groups), ' '.join(sorted(groups))

