from collections import defaultdict

def count_paths(n, m, labyrinth):
    MOD = 10**9 + 7

    # Initialize a 2D list to store the number of ways to reach each cell
    dp = [[0] * m for _ in range(n)]

    # Starting point
    dp[0][0] = 1

    # Fill the dp table
    for i in range(n):
        for j in range(m):
            if labyrinth[i][j] == '.':
                # Move right
                if j < m - 1:
                    dp[i][j + 1] = (dp[i][j + 1] + dp[i][j]) % MOD
                # Move down
                if i < n - 1:
                    dp[i + 1][j] = (dp[i + 1][j] + dp[i][j]) % MOD

    return dp[n - 1][m - 1]

from typing import *
from collections import *

def count_nice_integers(a: int, b: int) -> int:
    MOD = 1_000_000_007
    if a == 1:
        return 0

    # Calculate the number of nice integers
    nice_count = 0
    for x in range(1, a + 1):
        if x % b != 0 and x // b != x % b:
            nice_count += 1

    return nice_count % MOD

