from functools import lru_cache

@lru_cache(None)
def count_paths(n, m, x, y, rocks):
    if x == n or y == m:
        return 0 if rocks else 1

    if (x, y) in rocks:
        return count_paths(n, m, x, y + 1, rocks) + count_paths(n, m, x + 1, y, rocks)

    return count_paths(n, m, x, y + 1, rocks) + count_paths(n, m, x + 1, y, rocks)

def solve_labyrinth(n, m, labyrinth):
    rocks = set()
    for i in range(n):
        for j in range(m):
            if labyrinth[i][j] == 'R':
                rocks.add((i, j))

    return count_paths(n, m, 1, 1, rocks) % (10**9 + 7)

