from collections import defaultdict
from typing import List

def count_paths(n: int, m: int, labyrinth: List[str]) -> int:
    MOD = 10**9 + 7

    # Initialize a 2D list to store the number of ways to reach each cell
    dp = [[0] * m for _ in range(n)]

    # Starting cell
    dp[0][0] = 1

    # Fill the dp table
    for i in range(n):
        for j in range(m):
            if labyrinth[i][j] == '.':
                if i > 0:
                    dp[i][j] = (dp[i][j] + dp[i-1][j]) % MOD
                if j > 0:
                    dp[i][j] = (dp[i][j] + dp[i][j-1]) % MOD

    return dp[n-1][m-1]

def count_nice_integers(a, b):
    MOD = 10**9 + 7
    nice_count = 0

    # Iterate through all numbers from 1 to a
    for x in range(1, a + 1):
        # Check if x is nice
        if x % b != 0 and x // b == x % b:
            nice_count += 1

    return nice_count % MOD

