from collections import Counter

def max_divisor_count(l, r):
    divisor_counts = Counter()
    for num in range(l, r + 1):
        for i in range(2, int(num**0.5) + 1):
            while num % i == 0:
                divisor_counts[i] += 1
                num //= i
        if num > 1:
            divisor_counts[num] += 1
    max_count = max(divisor_counts.values())
    return [divisor for divisor, count in divisor_counts.items() if count == max_count][0]

