def magic_call_depth_number(pattern):
    P = {}
    def filling(w):
        k, v = w.groups()
        P[k] = set(build(v))
        return ""

    def minimum(id1, S):
        if id1 in S: return (False, -1)
        if not P[id1]: return (True, 0)
        mini = float('inf')
        for id2 in P[id1]:
            b, x = minimum(id2, S|{id1})
            if b: return (True, 0)
            mini = min(mini, x+1)
        return (False, mini)

    def maximum(id1, S):
        if id1 in S: return (True, -1)
        if not P[id1]: return (False, 0)
        res, maxi = (False, 0)
        for id2 in P[id1]:
            b, x = maximum(id2, S|{id1})
            if b: res, maxi = res or b, max(maxi, x+1)
        return (res, maxi)

    P[None] = set(build(read(filling, pattern)))
    return [minimum(None, set())[1], maximum(None, set())[1]]

import re

class Pattern:
    def __init__(self, definition, patterns):
        self._name = re.findall("p([0-9]+)", definition)[0]
        self._calls = re.findall("P([0-9]+)", definition)
        patterns[self._name] = self

    def simulate(self, patterns, visited, depths, depth=0):
        if self._name in visited:
            depths.append(depth)
            return

        if len(self._calls) == 0:
            depths.append(0)
            return

        visited.add(self._name)
        for call in self._calls:
            patterns[call].simulate(patterns, visited, depths, depth+1)
        visited.remove(self._name)

def magic_call_depth_number(pattern):
    patterns = {}
    while True:
        match = re.search("p[0-9]+[^q]*q", pattern)
        if match == None:
            break
        (start, end) = match.span()
        pattern = pattern[0:start] + pattern[end:]
        Pattern(match.group(0), patterns)

    depths = []
    for e in re.findall("P([0-9]+)", pattern):
        visited = set()
        patterns[e].simulate(patterns, visited, depths)

    if len(depths) == 0:
        return [0, 0]
    else:
        return [min(depths), max(depths)]

import re

def magic_call_depth_number(pattern):
    subroutines = {} # list them by number
    s = re.compile(r'p(\d+)((P\d+|[FLR]*\d*)+)q')
    subrout = s.search(pattern)
    while subrout:
        # put the subroutine in the dictionary
        subroutines["P" + subrout.group(1)] = tokens(subrout.group(2))
        # extract this subroutine from the pattern and see if there are more
        pattern = pattern.replace(subrout.group(0), "")
        subrout = s.search(pattern)
    # Make a tree
    depths = walk_tree(tokens(pattern), [], subroutines)
    return [min(depths), max(depths)]

def tokens(pattern):
    return re.findall(r'([PFLR]\d*)', pattern)

def walk_tree(token_list, stack, subroutine_dict):
    depths = []
    stops_here = True
    for t in token_list:
        if t.startswith("P"):
            stops_here = False
            if t in stack:
                depths.append(len(stack))
            else:
                depths.extend(walk_tree(subroutine_dict[t], stack + [t], subroutine_dict))
    if stops_here:
        depths.append(0)
    return depths

