def magic_call_depth_number(pattern):
    def parse_pattern(pattern):
        stack = []
        current_pattern = ""
        for char in pattern:
            if char == "p":
                if current_pattern:
                    stack.append(current_pattern)
                current_pattern = ""
            elif char == "q":
                if current_pattern:
                    stack.append(current_pattern)
                current_pattern = ""
            elif char.isdigit():
                current_pattern += char
            elif char == "F" or char == "L" or char == "R":
                if current_pattern:
                    stack.append(current_pattern)
                current_pattern = ""
                stack.append(char)
        if current_pattern:
            stack.append(current_pattern)
        return stack

    def dfs(stack, depth=0):
        if not stack:
            return depth
        current_pattern = stack.pop()
        if current_pattern.isdigit():
            return dfs(stack, depth + 1)
        elif current_pattern == "P":
            return dfs(stack, depth)
        else:
            return max(dfs(stack, depth), dfs(stack, depth + 1))

    stack = parse_pattern(pattern)
    min_depth = dfs(stack)
    max_depth = dfs(stack)
    return [min_depth, max_depth]

