from collections import defaultdict
from functools import lru_cache

@lru_cache(None)
def count_paths(n, m, x, y, visited):
    if x == n or y == m or visited[x][y]:
        return 0
    if x == n - 1 and y == m - 1:
        return 1

    visited[x][y] = True
    paths = count_paths(n, m, x + 1, y, visited) + count_paths(n, m, x, y + 1, visited)
    visited[x][y] = False

    return paths % (10**9 + 7)

def count_paths_to_goal(n, m, labyrinth):
    visited = [[False] * m for _ in range(n)]
    return count_paths(n, m, 0, 0, visited)

def arithmetic_sequence_sum(a1, d, n):
    if not isinstance(a1, (int, float)) or not isinstance(d, (int, float)) or not isinstance(n, int):
        raise ValueError("All inputs must be integers or floats.")
    if n <= 0:
        raise ValueError("n must be a positive integer.")
    return n / 2 * (2 * a1 + (n - 1) * d)

def find_missing_number(sequence):
    # Check if the sequence has at least two elements
    if len(sequence) < 2:
        raise ValueError("Sequence must have at least two elements")

    # Calculate the common difference between consecutive elements
    common_difference = (sequence[-1] - sequence[0]) / (len(sequence) - 1)

    # Find the missing number
    for i in range(1, len(sequence)):
        expected_value = sequence[i-1] + common_difference
        if sequence[i] != expected_value:
            return expected_value

    # If no missing number is found, the sequence is already complete
    return None

def fibonacci_modulo(n, m):
    if n == 0:
        return 0
    elif n == 1:
        return 1

    a, b = 0, 1
    for _ in range(2, n + 1):
        a, b = b, (a + b) % m

    return b

def find_nth_fibonacci_modulo(m, n):
    # Base cases
    if n == 1 or n == 2:
        return 1

    # Initialize the first two Fibonacci numbers
    a, b = 1, 1

    # Calculate the nth Fibonacci number modulo m
    for _ in range(3, n + 1):
        a, b = b, (a + b) % m

    return b

def sum_of_multiples(n):
    if n < 3:
        return 0
    return sum(i for i in range(3, n + 1, 3)) + sum(i for i in range(5, n + 1, 5))

