from typing import List

def count_paths(n: int, m: int, labyrinth: List[str]) -> int:
    MOD = 10**9 + 7

    # Check if the start or end cell has a rock
    if labyrinth[0][0] == 'R' or labyrinth[n-1][m-1] == 'R':
        return 0

    # Create a 2D array to store the number of ways to reach each cell
    dp = [[0] * m for _ in range(n)]

    # Initialize the starting cell
    dp[0][0] = 1

    # Fill the dp array
    for i in range(n):
        for j in range(m):
            if labyrinth[i][j] == '.':
                if i > 0:
                    dp[i][j] = (dp[i][j] + dp[i-1][j]) % MOD
                if j > 0:
                    dp[i][j] = (dp[i][j] + dp[i][j-1]) % MOD

    return dp[n-1][m-1]

def two_sum(nums, target):
    seen = {}
    for i, num in enumerate(nums):
        complement = target - num
        if complement in seen:
            return [seen[complement], i]
        seen[num] = i
    return []

def fibonacci(n):
    if n <= 0:
        return "Input should be a positive integer."
    elif n == 1:
        return 0
    elif n == 2:
        return 1
    else:
        a, b = 0, 1
        for _ in range(2, n):
            a, b = b, a + b
        return b

def sum_of_arithmetic_sequence(a1, d, n):
    if not isinstance(a1, int) or not isinstance(d, int) or not isinstance(n, int):
        raise ValueError("All arguments must be integers")
    if n <= 0:
        raise ValueError("Number of terms must be positive")
    return n // 2 * (2 * a1 + (n - 1) * d)

def longest_arithmetic_subsequence(nums):
    if not nums:
        return 0

    # Dictionary to store the length of the longest arithmetic subsequence ending at each index
    dp = {i: 1 for i in range(len(nums))}

    # Iterate through the array to fill the dp dictionary
    for i in range(1, len(nums)):
        for j in range(i):
            if nums[i] - nums[j] == nums[j] - nums[i-1]:
                dp[i] = max(dp[i], dp[j] + 1)

    # Return the maximum value found in the dp dictionary
    return max(dp.values())

def max_subarray_sum(nums):
    if not nums:
        return 0

    max_current = max_global = nums[0]

    for num in nums[1:]:
        max_current = max(num, max_current + num)
        max_global = max(max_global, max_current)

    return max_global

def fibonacci(n):
