def max_product_pair(nums):
    if len(nums) < 2:
        raise ValueError("Input array must contain at least two elements")

    # Initialize variables to store the maximum and second maximum products
    max_product = float('-inf')
    second_max_product = float('-inf')

    # Iterate through the array to find the maximum and second maximum products
    for num in nums:
        if num > max_product:
            second_max_product = max_product
            max_product = num
        elif num > second_max_product and num != max_product:
            second_max_product = num

    return max_product * second_max_product

def arithmetic_sequence_sum(a, d, n):
    # Check if input values are valid
    if not isinstance(a, (int, float)) or not isinstance(d, (int, float)) or not isinstance(n, int):
        raise ValueError("All inputs must be integers or floats.")
    if n <= 0:
        raise ValueError("n must be a positive integer.")

    # Calculate the sum of the arithmetic sequence
    sum_of_sequence = (n / 2) * (2 * a + (n - 1) * d)

    return sum_of_sequence

def arithmetic_sequence_sum(a, d, n):
    # Check if input values are valid
    if not isinstance(a, (int, float)) or not isinstance(d, (int, float)) or not isinstance(n, int):
        raise ValueError("All inputs must be integers or floats.")
    if n <= 0:
        raise ValueError("n must be a positive integer.")

    # Calculate the sum of the arithmetic sequence
    sum_of_sequence = (n / 2) * (2 * a + (n - 1) * d)

    return sum_of_sequence

def largest_prime_factor(n):
    if n <= 1:
        return None
    largest_factor = None
    # Divide n by 2 until it's odd
    while n % 2 == 0:
        largest_factor = 2
        n //= 2
    # Check for odd factors from 3 onwards
    for i in range(3, int(n**0.5) + 1, 2):
        while n % i == 0:
            largest_factor = i
            n //= i
    # If n is a prime number greater than 2
    if n > 2:
        largest_factor = n
    return largest_factor

