from collections import defaultdict

def group_websites(queries):
    hostname_to_queries = defaultdict(list)

    for query in queries:
        hostname, path = query.split('/')
        hostname_to_queries[hostname].append(path)

    groups = []
    for hostname, paths in hostname_to_queries.items():
        if len(paths) > 1:
            groups.append(hostname)

    return len(groups), ' '.join(groups)

