from typing import List

def count_paths(n: int, m: int, labyrinth: List[str]) -> int:
    MOD = 10**9 + 7

    # Initialize a 2D array to store the number of ways to reach each cell
    dp = [[0] * m for _ in range(n)]

    # Starting cell
    dp[0][0] = 1

    # Fill the first row
    for j in range(1, m):
        if labyrinth[0][j] == '.':
            dp[0][j] = dp[0][j-1]

    # Fill the first column
    for i in range(1, n):
        if labyrinth[i][0] == '.':
            dp[i][0] = dp[i-1][0]

    # Fill the rest of the dp table
    for i in range(1, n):
        for j in range(1, m):
            if labyrinth[i][j] == '.':
                dp[i][j] = (dp[i-1][j] + dp[i][j-1]) % MOD

    return dp[n-1][m-1]

