from typing import List

def arithmetic_progression_sum(nums: List[int]) -> int:
    n = len(nums)
    if n < 2:
        return 0

    # Sort the array to make it easier to find arithmetic subsequences
    nums.sort()

    total_sum = 0
    for i in range(n):
        for j in range(i + 1, n):
            diff = nums[j] - nums[i]
            for k in range(j + 1, n):
                if nums[k] - nums[j] == diff:
                    total_sum += nums[i] + nums[j] + nums[k]

    return total_sum

