def max_subarray_sum(nums: List[int], k: int) -> int:
    if not nums or k <= 0:
        return 0

    n = len(nums)
    if k > n:
        return sum(nums)

    current_sum = sum(nums[:k])
    max_sum = current_sum

    for i in range(k, n):
        current_sum = current_sum - nums[i-k] + nums[i]
        max_sum = max(max_sum, current_sum)

    return max_sum

def check_divisibility_and_primality(n):
    if not isinstance(n, int) or n <= 0:
        raise ValueError("Input must be a positive integer")

    # Check divisibility by 7
    is_divisible_by_7 = n % 7 == 0

    # Check if the number is prime
    if n <= 1:
        is_prime = False
    elif n <= 3:
        is_prime = True
    else:
        is_prime = n % 2 != 0 and n % 3 != 0
        for i in range(5, int(n**0.5) + 1, 6):
            if n % i == 0 or n % (i + 2) == 0:
                is_prime = False

    return (is_divisible_by_7, is_prime)

def max_non_overlapping_subarrays(nums):
    n = len(nums)
    if n < 2:
        return 0

    # Initialize variables to store the maximum sum of non-overlapping subarrays
    max_sum = 0
    current_sum = 0
    start = 0

    # Iterate through the array to find the maximum sum of non-overlapping subarrays
    for end in range(n):
        current_sum += nums[end]

        # If the current sum exceeds the maximum sum, update the maximum sum and reset the start index
        if current_sum > max_sum:
            max_sum = current_sum
            start = end

        # If the current sum becomes negative, reset it to zero
        if current_sum < 0:
            current_sum = 0

    # Calculate the maximum sum of non-overlapping subarrays by subtracting the minimum value of the two subarrays from the total sum
    return max_sum - min(nums[start:end+1])

