from collections import defaultdict

def group_websites(queries):
    # Dictionary to store the set of queries for each hostname
    hostname_queries = defaultdict(set)

    # Process each query
    for query in queries:
        hostname, path = query.split('/')
        hostname_queries[hostname].add(path)

    # Find groups of websites
    groups = []
    for hostname, paths in hostname_queries.items():
        if len(paths) > 1:
            groups.append(hostname)

    # Return the number of groups and the groups themselves
    return len(groups), ' '.join(groups)

