from collections import Counter

def find_spec_prod_part(n, com):
    if n <= 0:
        return "Invalid input"

    if n in [2, 3]:
        return "It is a prime number"

    def prime_factors(n):
        i = 2
        factors = []
        while i * i <= n:
            if n % i:
                i += 1
            else:
                n //= i
                factors.append(i)
        if n > 1:
            factors.append(n)
        return factors

    def score(partition):
        prime_factors_count = Counter(prime_factors(partition))
        return sum((value + 1) * value // 2 for value in prime_factors_count.values())

    partitions = []
    for i in range(2, n + 1):
        if n % i == 0:
            factors = prime_factors(i)
            for j in range(len(factors)):
                for k in range(j + 1, len(factors)):
                    for l in range(k + 1, len(factors)):
                        for m in range(l + 1, len(factors)):
                            for n in range(m + 1, len(factors)):
                                partition = [factors[j], factors[k], factors[l], factors[m], factors[n]]
                                partitions.append([partition, score(partition)])

    if com == 'max':
        return max(partitions, key=lambda x: x[1])
    elif com == 'min':
        return min(partitions, key=lambda x: x[1])
    else:
        return "Invalid command"

