from typing import List

def count_arithmetic_progressions(n: int) -> int:
    if n <= 0:
        return 0

    # Initialize a list to store the number of APs ending at each number
    dp = [0] * (n + 1)

    # Base case: There's one AP ending at each number (the number itself)
    for i in range(1, n + 1):
        dp[i] = 1

    # Fill the dp array
    for i in range(2, n + 1):
        for j in range(i):
            if (i - j) % 2 == 0:
                dp[i] += dp[j]

    # The total number of APs is the sum of all dp values
    return sum(dp)

def sum_of_even_numbers(sequence):
    total = 0
    for number in sequence:
        if number % 2 == 0:
            total += number
    return total

from typing import List

def longestArithmeticSequence(stones: List[int]) -> int:
    if not stones:
        return 0

    stones.sort()
    n = len(stones)
    dp = [[1] * n for _ in range(n)]

    for i in range(1, n):
        for j in range(i):
            if stones[i] - stones[j] == stones[j] - stones[j - 1]:
                dp[i][j] = dp[j][j - 1] + 1

    return max(max(row) for row in dp)

