def partitions(factors):
    if len(factors) == 1:
        yield factors[0],
        return
    first = factors[0]
    for subpart in partitions(factors[1:]):
        for n, fact in enumerate(subpart):
            yield tuple(sorted(subpart[:n] + (first * fact,) + subpart[n+1:], reverse=True))
        yield tuple(sorted((first,) + subpart, reverse=True))

