from collections import Counter

def find_spec_prod_part(n, com):
    if n <= 0:
        return "Invalid input"

    if n in [2, 3]:
        return "It is a prime number"

    prime_factors = []
    divisor = 2
    while divisor * divisor <= n:
        while n % divisor == 0:
            prime_factors.append(divisor)
            n //= divisor
        divisor += 1

    if n > 1:
        prime_factors.append(n)

    prime_counts = Counter(prime_factors)
    max_score = float('-inf')
    min_score = float('inf')
    max_partition = None
    min_partition = None

    for partition in product(range(1, len(prime_factors) + 1), repeat=len(prime_factors)):
        score = sum((prime_counts[p] + 1) * p for p in partition)
        if com == 'max':
            if score > max_score:
                max_score = score
                max_partition = partition
        elif com == 'min':
            if score < min_score:
                min_score = score
                min_partition = partition

    if max_partition is None:
        return "No valid partition found"

    return [sorted(max_partition, reverse=True), max_score]

