from typing import List

def count_paths(n: int, m: int, labyrinth: List[str]) -> int:
    MOD = 10**9 + 7

    # Initialize the DP table
    dp = [[0] * m for _ in range(n)]

    # Starting cell
    dp[0][0] = 1

    # Fill the DP table
    for i in range(n):
        for j in range(m):
            if labyrinth[i][j] == '.':
                # Move right
                if j < m - 1:
                    dp[i][j + 1] = (dp[i][j + 1] + dp[i][j]) % MOD
                # Move down
                if i < n - 1:
                    dp[i + 1][j] = (dp[i + 1][j] + dp[i][j]) % MOD

    return dp[n - 1][m - 1]

from typing import List

def kth_smallest_prime_factor(n: int, k: int) -> int:
    if n <= 1 or k <= 0:
        raise ValueError("Input must be a positive integer and k must be positive.")

    def is_prime(num):
        if num <= 1:
            return False
        if num == 2:
            return True
        if num % 2 == 0:
            return False
        for i in range(3, int(num**0.5) + 1, 2):
            if num % i == 0:
                return False
        return True

    prime_factors = []
    for i in range(2, n + 1):
        while n % i == 0:
            prime_factors.append(i)
            n //= i

    if len(prime_factors) < k:
        raise ValueError("There are not enough prime factors for the given n and k.")

    return prime_factors[k - 1]

from typing import List

def sum_of_arithmetic_progressions(nums: List[int]) -> int:
    if not nums:
        return 0

    # Sort the list to easily identify APs
    nums.sort()

    total_sum = 0
    start = 0

    for end in range(1, len(nums)):
        # Check if the current subarray forms an AP
        if nums[end] - nums[start] == nums[end - 1] - nums[start]:
            total_sum += sum(nums[start:end + 1])
        else:
            start = end

    return total_sum

def find_gcd(num1: int, num2: int) -> int:
    # Ensure num1 is always greater than or equal to num2
    if num2 > num1:
        num1, num2 = num2, num1

    # Base case: if num2 is 0, num1 is the GCD
    if num2 == 0:
        return num1

    # Recursive case: apply Euclidean algorithm
    return find_gcd(num2, num1 % num2)

def arithmetic_sequence_sum(a, d, n):
    if not isinstance(n, int) or n <= 0:
        raise ValueError("n must be a positive integer")
    return n // 2 * (2 * a + (n - 1) * d)

def largest_prime_factor(n):
    # Initialize the largest prime factor as 1
    largest_prime = 1

    # Divide n by 2 until it's odd
    while n % 2 == 0:
        largest_prime = 2
        n //= 2

    # Check for odd factors starting from 3
    for i in range(3, int(n**0.5) + 1, 2):
        while n % i == 0:
            largest_prime = i
            n //= i

    # If n is a prime number greater than 2
    if n > 2:
        largest_prime = n

    return largest_prime
